module parallel_load_register
    (
        input rst_n,
        input obf_clk,
        input load,
        input [5:0] data,
        output reg [5:0] q
    );

    always @(posedge obf_clk or negedge rst_n) 
    begin
        if (!rst_n)
            q <= 6'd0;
        else if (load)
            q <= data;
    end

endmodule
